 3	import { useTranslation } from 'react-i18next';
 4	import { MetricScopeOptions } from '../../model/metrics';
 5	import { getGroupName, getGroupsForScope, ScopeConfigDef } from '../../model/scope';
 6	import { TopologyGroupTypes } from '../../model/topology';
 7	
 8	export interface GroupDropdownProps {
 9	  disabled?: boolean;
10	  scope: MetricScopeOptions;
11	  selected: TopologyGroupTypes;
12	  setGroupType: (v: TopologyGroupTypes) => void;
13	  id?: string;
14	  scopes: ScopeConfigDef[];
15	}
16	
17	export const GroupDropdown: React.FC<GroupDropdownProps> = ({
18	  disabled,
19	  scope,
20	  selected,
21	  setGroupType,
22	  id,
23	  scopes
24	}) => {
25	  const { t } = useTranslation('plugin__netobserv-plugin');
26	  const [isOpen, setOpen] = React.useState(false);
27	
28	  return (
29	    <Dropdown
30	      data-test={id}
31	      id={id}
32	      isOpen={isOpen}
33	      toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
34	        <MenuToggle
35	          ref={toggleRef}
36	          data-test={`${id}-dropdown`}
37	          id={`${id}-dropdown`}
38	          isDisabled={disabled}
39	          isExpanded={isOpen}
40	          onClick={() => setOpen(!isOpen)}
41	          onBlur={() => setTimeout(() => setOpen(false), 500)}
42	        >
43	          {getGroupName(selected, scopes, t)}
44	        </MenuToggle>
45	      )}
46	    >
47	      {getGroupsForScope(scope, scopes).map(v => (
48	        <DropdownItem
49	          data-test={v}
50	          id={v}
51	          key={v}
52	          onClick={() => {
53	            setOpen(false);
54	            setGroupType(v);
55	          }}
56	        >
57	          {getGroupName(v, scopes, t)}
58	        </DropdownItem>
59	      ))}
60	    </Dropdown>
61	  );
62	};
63	
64	export default GroupDropdown;

