 1	import { act, fireEvent, render, screen, waitFor } from '@testing-library/react';
 2	import userEvent from '@testing-library/user-event';
 3	import * as React from 'react';
 4	
 5	import { ScopeDefSample } from '../../../components/__tests-data__/scopes';
 6	import { MetricScopeOptions } from '../../../model/metrics';
 7	import { GroupDropdown } from '../group-dropdown';
 8	
 9	describe('<GroupDropdown />', () => {
10	  const props = {
11	    scope: MetricScopeOptions.RESOURCE,
12	    selected: 'hosts',
13	    setGroupType: jest.fn(),
14	    id: 'group',
15	    scopes: ScopeDefSample
16	  };
17	
18	  it('should render component', async () => {
19	    render(<GroupDropdown {...props} />);
20	    expect(screen.getByRole('button')).toHaveAttribute('id', 'group-dropdown');
21	  });
22	
23	  it('should open and close', async () => {
24	    const { container } = render(<GroupDropdown {...props} />);
25	
26	    await act(async () => {
27	      fireEvent.click(container.querySelector('#group-dropdown')!);
28	    });
29	    await waitFor(() => {
30	      expect(document.querySelectorAll('[role="menu"] li').length).toBeGreaterThan(0);
31	    });
32	
33	    await act(async () => {
34	      fireEvent.click(container.querySelector('#group-dropdown')!);
35	    });
36	
37	    expect(props.setGroupType).toHaveBeenCalledTimes(0);
38	  });
39	
40	  it('should refresh on select', async () => {
41	    const user = userEvent.setup();
42	    const { container } = render(<GroupDropdown {...props} />);
43	
44	    await act(async () => {
45	      fireEvent.click(container.querySelector('#group-dropdown')!);
46	    });
47	    await waitFor(() => expect(document.querySelector('#none')).toBeTruthy());
48	
49	    await user.click(document.querySelector('#none')!);
50	    expect(props.setGroupType).toHaveBeenCalledWith('none');
51	
52	    await act(async () => {
53	      fireEvent.click(container.querySelector('#group-dropdown')!);
54	    });
55	    await waitFor(() => expect(document.querySelector('#owners')).toBeTruthy());
56	
57	    await user.click(document.querySelector('#owners')!);
58	
59	    expect(props.setGroupType).toHaveBeenCalledTimes(2);
60	    expect(props.setGroupType).toHaveBeenCalledWith('owners');
61	  });
62	});

